mapper.insert:
insert into knowledge_document (
    project_id, knowledge_base_id, file_id, title, source_type, index_status,
    version_no, created_by, updated_by
) values (
    #{projectId}, #{knowledgeBaseId}, #{fileId}, #{title}, #{sourceType}, #{indexStatus},
    #{versionNo}, #{createdBy}, #{updatedBy}
)

mapper.update:
update knowledge_document
set index_status = 'INDEXING',
    error_message = null,
    updated_by = #{updatedBy}
where id = #{documentId}
  and deleted = 0

update knowledge_document
set index_status = 'SUCCESS',
    error_message = null,
    updated_by = #{updatedBy}
where id = #{documentId}
  and deleted = 0

update knowledge_document
set index_status = 'FAILED',
    error_message = #{errorMessage},
    updated_by = #{updatedBy}
where id = #{documentId}
  and deleted = 0

update knowledge_document
set deleted = 1, updated_by = #{updatedBy}
where id = #{documentId}
  and deleted = 0
